  options = arpack_defaults()
) {
  # Argument checks
  ensure_igraph(graph)
  algorithm <- switch_igraph_arg(
    algorithm,
    "auto" = 0L,
    "lapack" = 1L,
    "arpack" = 2L,
    "comp_auto" = 3L,
    "comp_lapack" = 4L,
    "comp_arpack" = 5L
  )
  which.tmp <- eigen_defaults()
  which.tmp[names(which)] <- which
  which <- which.tmp
  options <- modify_list(arpack_defaults(), options)

  on.exit(.Call(R_igraph_finalizer))
  # Function call
  res <- .Call(
    R_igraph_eigen_adjacency,
    graph,
    algorithm,
    which,
    options
  )

  res
}

