ecc_impl <- function(
  graph,
  eids = E(graph),
  k = 3,
  offset = FALSE,
  normalize = TRUE
) {
  # Argument checks
  ensure_igraph(graph)
  eids <- as_igraph_es(graph, eids)
  k <- as.numeric(k)
  offset <- as.logical(offset)
  normalize <- as.logical(normalize)

  on.exit(.Call(R_igraph_finalizer))
  # Function call
  res <- .Call(
    R_igraph_ecc,
    graph,
    eids - 1,
    k,
    offset,
    normalize
  )

  res
}

